LinK11:
这是笔者第一次接触深度优先搜索（DFS），即一条路走到底（参考电影：明日边缘）
a 存当前排列，book 标记数字是否用过，step 代表当前填第几位。
DFS逻辑：step=n+1：排列填满，打印；
循环 1~n，没用过的数字填入，标记后递归下一位，递归返回取消标记（回溯）。
核心：回溯，用完数字撤销标记，枚举所有组合
源码：
#include<iostream>
using namespace std;
int a[50];  //保存当前排列
int book[50];  //标记数字是否被选用
int n;
void dfs(int step){
    if(step==n+1){ //所有位置填完
        for(int i=1;i<=n;i++){
            cout<<a[i]<<" ";
        }
            cout<<endl;
            return ;

    }
    for(int i=1;i<=n;i++){
        if(book[i]==0){  //i未被选用
            a[step]=i;
            book[i]=1;  //标记占用
            dfs(step+1);
            book[i]=0;  回溯，取消标记
        }
    }
}
int main(){
    cin>>n;
    dfs(1);
    return 0;
}

