#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
using namespace std;

string s;
int n;
vector<bool> used;
vector<char> path;

void dfs() {
    if (path.size() == n) {
        for (char c : path) cout << c;
        cout << endl;
        return;
    }

    for (int i = 0; i < n; i++) {
        if (used[i]) continue;
        if (i > 0 && s[i] == s[i-1] && !used[i-1]) continue;

        used[i] = true;
        path.push_back(s[i]);
        dfs();
        path.pop_back();
        used[i] = false;
    }
}

int main() {
    cin >> s;
    n = s.size();
    sort(s.begin(), s.end()); 
    used.assign(n, false);
    dfs();
    return 0;
}

LinK13:
DFS的经典题目，任意两个皇后不可同行同列或者同对角线
详细题解看注释
源码：
#include <iostream>
#include <vector>
using namespace std;

vector<vector<int> > res;  //保存所有合法n皇后的完整方案
vector<int> path;  path【r】代表第r行皇后放在第几列
int n;  //棋盘大小

bool check(int row, int col)。//用于检查第row行第col列放皇后回不回和上一行的皇后冲突
{
    for (int r = 0; r < row; ++r)  //遍历上面每一行已经放置的皇后
    {
        int c = path[r];  r皇后所在列
        if (c == col || r - c == row - col || r + c == row + col)。//冲突三种情况
            return false;
    }
    return true;  
}

void dfs(int row)  处理第row行
{
    if (row == n)。//递归终止
    {
        res.push_back(path);
        return;
    }
    for (int col = 0; col < n; ++col)。//枚举当前行的每一列，尝试放皇后
    {
        if (check(row, col))。//如果合法
        {
            path.push_back(col);  //记录：第row行呼皇后放在地col列
            dfs(row + 1);  //递归处理下一行
            path.pop_back();  回溯，尝试下一列
        }
    }
}

int main()
{
    cin >> n;
    dfs(0);  从第0行开始
    for(int i=0;i<res.size();i++){
    	vector<int> temp=res[i];
    	for(int j=0;j<temp.size();j++){
    		cout<< temp[j]+1;
		}
		cout<<endl;
	}
	return 0;
}

